// ── load GSAP from CDN once ──────────────────────────────────────────────────
function useGsap() {
  const [gsap, setGsap] = useState(null);
  useEffect(() => {
    if (window.gsap) { setGsap(window.gsap); return; }
    const s = document.createElement("script");
    s.src = "https://cdnjs.cloudflare.com/ajax/libs/gsap/3.12.5/gsap.min.js";
    s.onload = () => setGsap(window.gsap);
    document.body.appendChild(s);
  }, []);
  return gsap;
}

function CheckOne({ color = BRAND }) {
  return (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none">
      <circle cx="12" cy="12" r="10" fill={color} />
      <path d="M7.5 12.2l3 3 6-6.4" stroke="#fff" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round" />
    </svg>
  );
}
function AutoVideo({ src, style }) {
  const ref = useRef(null);
  useEffect(() => {
    const v = ref.current;
    if (!v) return;
    v.muted = true;
    v.defaultMuted = true;
    const tryPlay = () => { const p = v.play(); if (p && p.catch) p.catch(() => {}); };
    tryPlay();
    // retry once loaded in case the first attempt was too early
    v.addEventListener("loadeddata", tryPlay);
    return () => v.removeEventListener("loadeddata", tryPlay);
  }, [src]);
  return <video ref={ref} src={src} autoPlay loop muted playsInline preload="auto" style={style} />;
}
