function HowItWorks({ steps, iconSet = "shoot", gsap }) {
  const wrap = useRef(null);
  const badgeRefs = useRef([]);
  const iconRefs = useRef([]);
  const labelRefs = useRef([]);
  const lineRef = useRef(null);

  useEffect(() => {
    if (!gsap || !wrap.current) return;
    const badges = badgeRefs.current.filter(Boolean);
    const icons = iconRefs.current.filter(Boolean);
    const labels = labelRefs.current.filter(Boolean);
    const STEP = 0.16; // gap between steps loading in
    let played = false;

    // set initial hidden state up front so nothing flashes before the section is seen
    gsap.set(badges, { scale: 0.92, opacity: 0, y: 6 });
    gsap.set(icons, { opacity: 0 });
    gsap.set(labels, { y: 4, opacity: 0 });
    if (lineRef.current) gsap.set(lineRef.current, { scaleX: 0, transformOrigin: "left center" });

    const play = () => {
      if (played) return;
      played = true;
      const ctx = gsap.context(() => {
        if (lineRef.current) gsap.to(lineRef.current, { scaleX: 1, duration: 0.9, ease: "power1.out", delay: 0.05 });
        // each step eases in gently, one by one — then stays put
        badges.forEach((b, i) => {
          const t = 0.1 + i * STEP;
          gsap.to(b, { scale: 1, opacity: 1, y: 0, duration: 0.45, ease: "power2.out", delay: t });
          if (icons[i]) gsap.to(icons[i], { opacity: 1, duration: 0.4, ease: "power1.out", delay: t + 0.06 });
          if (labels[i]) gsap.to(labels[i], { y: 0, opacity: 1, duration: 0.4, ease: "power2.out", delay: t + 0.1 });
        });
      }, wrap);
    };

    let io;
    if (typeof IntersectionObserver !== "undefined") {
      io = new IntersectionObserver((entries) => {
        entries.forEach((e) => { if (e.isIntersecting) { play(); io.disconnect(); } });
      }, { threshold: 0.4 });
      io.observe(wrap.current);
    } else {
      play(); // fallback: no observer support
    }
    return () => { if (io) io.disconnect(); };
  }, [gsap]);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <span style={{ fontSize: 12, fontWeight: 600, color: "#000", letterSpacing: "-0.12px" }}>How it works</span>
      <div ref={wrap} style={{ position: "relative", display: "flex", justifyContent: "space-between", alignItems: "flex-start", padding: "8px 6px 0" }}>
        {/* connector line behind the badges */}
        <div style={{ position: "absolute", top: 30, left: "12%", right: "12%", height: 3, background: "#ece4ff", borderRadius: 3, overflow: "hidden" }}>
          <div ref={lineRef} style={{ width: "100%", height: "100%", background: "linear-gradient(90deg,#7f6af2,#4600f2)", borderRadius: 3 }} />
        </div>
        {steps.map((step, i) => (
          <div key={i} style={{ flex: 1, minWidth: 0, display: "flex", flexDirection: "column", alignItems: "center", gap: 8, position: "relative", zIndex: 1 }}>
            <div ref={(el) => (badgeRefs.current[i] = el)} style={{ width: 48, height: 48, borderRadius: "50%", background: "linear-gradient(150deg,#7f6af2,#4600f2)", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: "0 6px 16px rgba(70,0,242,0.35)", position: "relative" }}>
              <span ref={(el) => (iconRefs.current[i] = el)} style={{ display: "inline-flex", alignItems: "center", justifyContent: "center" }}>
                <HowStepIcon set={iconSet} kind={i} />
              </span>
              <span style={{ position: "absolute", top: -4, right: -4, width: 18, height: 18, borderRadius: "50%", background: "#fff", border: "1.5px solid #ece4ff", color: BRAND, fontSize: 10, fontWeight: 700, display: "flex", alignItems: "center", justifyContent: "center" }}>{i + 1}</span>
            </div>
            <span ref={(el) => (labelRefs.current[i] = el)} style={{ fontSize: 11, fontWeight: 600, color: "#3a3a3a", textAlign: "center", lineHeight: "14px", maxWidth: 92 }}>{step}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

