            <div style={{ position: "absolute", top: -90, right: "8%", width: 400, height: 400, borderRadius: "50%", background: "radial-gradient(circle, rgba(232,62,84,0.12), rgba(232,62,84,0) 68%)", filter: "blur(10px)", animation: "apBlobFloat 16s ease-in-out infinite 1.4s" }} />
