function PointerIcon({ kind, color }) {
  const p = { fill: "none", stroke: color, strokeWidth: 1.9, strokeLinecap: "round", strokeLinejoin: "round" };
  const m = {
    flow: <g {...p}><rect x="3" y="4" width="6" height="6" rx="1.5" /><rect x="15" y="14" width="6" height="6" rx="1.5" /><path d="M9 7h4a2 2 0 0 1 2 2v6" /></g>,
    clock: <g {...p}><circle cx="12" cy="12" r="9" /><path d="M12 7v5l3 2" /></g>,
    spark: <g {...p}><path d="M12 3l1.7 5.1a3 3 0 0 0 1.9 1.9L21 11.7l-5.4 1.7a3 3 0 0 0-1.9 1.9L12 21l-1.7-5.7a3 3 0 0 0-1.9-1.9L3 11.7l5.4-1.7a3 3 0 0 0 1.9-1.9z" /></g>,
    globe: <g {...p}><circle cx="12" cy="12" r="9" /><path d="M3 12h18M12 3c2.5 2.5 2.5 15 0 18M12 3c-2.5 2.5-2.5 15 0 18" /></g>,
  };
  return <svg width="22" height="22" viewBox="0 0 24 24">{m[kind]}</svg>;
}

function StudioGlyph({ type, color = "#fff" }) {
  const c = { width: 38, height: 38, viewBox: "0 0 24 24", fill: "none", stroke: color, strokeWidth: 2, strokeLinecap: "round", strokeLinejoin: "round" };
  if (type === "bolt") return (<svg {...c}><path d="M13 2 4 14h6l-1 8 9-12h-6z" fill={color} stroke="none" /></svg>);
  if (type === "camera") return (<svg {...c}><path d="M3 8a2 2 0 0 1 2-2h2l1.5-2h7L19 6h0a2 2 0 0 1 2 2v9a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2z" /><circle cx="12" cy="13" r="3.2" /></svg>);
  if (type === "send") return (<svg {...c}><path d="M22 2 11 13" /><path d="M22 2 15 22l-4-9-9-4z" /></svg>);
  if (type === "spark") return (<svg {...c}><path d="M12 3l1.8 5.4a3 3 0 0 0 1.9 1.9L21 12l-5.3 1.7a3 3 0 0 0-1.9 1.9L12 21l-1.8-5.4a3 3 0 0 0-1.9-1.9L3 12l5.3-1.7a3 3 0 0 0 1.9-1.9z" fill={color} stroke="none" /></svg>);
  return (<svg {...c}><path d="M3 11v2a1 1 0 0 0 1 1h2l4 4V7L6 11H4a1 1 0 0 0-1 0z" fill={color} stroke="none" /><path d="M16 8a5 5 0 0 1 0 8" /><path d="M19 5a9 9 0 0 1 0 14" /></svg>);
}

function ProductGallery({ prod }) {
  const imgs = prod.gallery || [];
  if (!imgs.length) return null;
  const main = imgs[0];
  return (
    <div style={{ position: "relative", width: "100%", height: 250, borderRadius: 18, overflow: "hidden", border: "1px solid rgba(0,0,0,0.06)", boxShadow: `0 24px 50px -22px ${prod.glow}` }}>
      <img key={prod.key} src={main.src} alt={main.cap} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block", animation: "sosImgIn 0.4s ease both" }} />
      <div style={{ position: "absolute", left: 0, right: 0, bottom: 0, padding: "26px 16px 12px", background: "linear-gradient(180deg, rgba(0,0,0,0), rgba(0,0,0,0.55))" }}>
        <span style={{ fontSize: 13, fontWeight: 600, color: "#fff", letterSpacing: "0.1px" }}>{main.cap}</span>
      </div>
    </div>
  );
}

