      {/* centered gallery — glassmorphism outer card */}
      <div key={prod.key + "-gw"} style={{ position: "relative", width: 652, maxWidth: "100%", marginTop: 22, padding: 8, borderRadius: 28, background: "rgba(255,255,255,0.55)", backdropFilter: "blur(14px) saturate(160%)", WebkitBackdropFilter: "blur(14px) saturate(160%)", border: "1px solid rgba(255,255,255,0.7)", boxShadow: "0 18px 44px -22px rgba(40,35,80,0.28), inset 0 1px 0 rgba(255,255,255,0.6)", boxSizing: "border-box", animation: "sosImgIn 0.5s ease both" }}>
        {/* running edge light */}
        <div className="sosEdgeLight" style={{ position: "absolute", inset: 0, borderRadius: 28, padding: 1.5, pointerEvents: "none", background: "conic-gradient(from var(--sosAngle,0deg), transparent 0%, transparent 70%, rgba(255,255,255,0.9) 84%, rgba(255,255,255,0) 92%, transparent 100%)", WebkitMask: "linear-gradient(#000 0 0) content-box, linear-gradient(#000 0 0)", WebkitMaskComposite: "xor", maskComposite: "exclude" }} />
        <div style={{ position: "relative", width: "100%", aspectRatio: "16 / 9", borderRadius: 18, overflow: "hidden", border: "1px solid rgba(40,35,70,0.06)", boxShadow: `0 24px 50px -26px ${prod.glow}` }}>
          {img && <img src={img.src} alt={img.cap} style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />}
          <div style={{ position: "absolute", left: 0, right: 0, bottom: 0, padding: "30px 18px 14px", background: "linear-gradient(180deg, rgba(0,0,0,0), rgba(0,0,0,0.5))", textAlign: "left" }}>
            <span style={{ fontSize: 13, fontWeight: 600, color: "#fff" }}>{img && img.cap}</span>
          </div>
        </div>
      </div>

      {/* indicator dots */}
      <div style={{ display: "flex", gap: 8, marginTop: 20 }}>
        {STUDIO_PRODUCTS.map((p, i) => (
          <button key={p.key} onClick={() => onJump && onJump(i)} aria-label={`Show ${p.name}`}
            style={{ height: 8, width: i === idx ? 28 : 8, borderRadius: 999, border: "none", cursor: "pointer", padding: 0, background: i === idx ? prod.accent : "rgba(40,35,70,0.16)", transition: "width 0.35s ease, background 0.35s ease" }} />
        ))}
      </div>
