                  <svg width="13" height="13" viewBox="0 0 24 24" fill="none"><path d="M4 16l5-5 4 4 7-8" stroke="#6a4bf2" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round" /><path d="M15 7h5v5" stroke="#6a4bf2" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round" /></svg>
